import{_ as e,o as t,c as p,a2 as r}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"伯克希尔·哈撒韦公司1971年度致股东年报","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1971年/翻译.md","filePath":"01_letters/1971年/翻译.md"}'),o={name:"01_letters/1971年/翻译.md"};function l(h,a,i,n,s,d){return t(),p("div",null,[...a[0]||(a[0]=[r('<h1 id="伯克希尔·哈撒韦公司1971年度致股东年报" tabindex="-1">伯克希尔·哈撒韦公司1971年度致股东年报 <a class="header-anchor" href="#伯克希尔·哈撒韦公司1971年度致股东年报" aria-label="Permalink to &quot;伯克希尔·哈撒韦公司1971年度致股东年报&quot;">​</a></h1><p>（截至1972年1月1日，共52周）</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p>1-3页 董事长致辞</p><p>4页 会计师鉴证报告</p><p>财务报表：</p><p>5-10页 伯克希尔·哈撒韦公司及其合并子公司报表</p><p>未合并子公司报表：</p><p>11-16页 保险集团</p><p>17-21页 罗克福德市伊利诺伊国民银行与信托公司</p><hr><h2 id="致伯克希尔·哈撒韦公司全体股东" tabindex="-1">致伯克希尔·哈撒韦公司全体股东： <a class="header-anchor" href="#致伯克希尔·哈撒韦公司全体股东" aria-label="Permalink to &quot;致伯克希尔·哈撒韦公司全体股东：&quot;">​</a></h2><p>我们欣然向各位报告，1971年剔除资本利得后，公司营业收益达到期初股东权益的14%以上。尽管纺织业务盈利表现不佳，我们仍取得了这一远超美国行业平均水平的业绩，这充分印证了公司五年前启动的资本重新配置战略带来的成效。管理层将持续致力于提升总资本（长期债务+权益）回报率，同时提升权益资本回报率。但各位需要认识到，相较于60年代多数时间里公司从极低回报率水平实现的提升，如今即便只是维持当前相对较高的回报率，难度也会大得多。</p><h3 id="纺织业务" tabindex="-1">纺织业务 <a class="header-anchor" href="#纺织业务" aria-label="Permalink to &quot;纺织业务&quot;">​</a></h3><p>与行业内大多数企业一样，1971年全年我们的纺织业务持续受困于毛利率不足的困境。尽管我们大力压降成本、持续开发价格敏感度更低的面料品类，最终仅实现了微薄利润。但倘若没有这些努力，公司纺织业务将出现巨额亏损。得益于库存管控优化计划取得了合理成效，全年员工就业情况更为稳定。</p><p>正如去年年报中所提及，肯·蔡斯与其管理团队始终在与强大的行业逆风抗争。不利的行业环境反而让他们加倍付出努力。目前，行业已出现温和复苏迹象，我们将借助大幅扩充的销售团队，最大限度把握这一机遇。随着当前业务量与产品结构的改善，我们预计1972年纺织业务的盈利能力将有所提升——但不会出现爆发式增长。</p><h3 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h3><p>多重特殊因素的叠加——汽车事故发生率下降、大额业务线实际费率大幅上调，以及未发生重大巨灾事故，为财产意外险行业带来了业绩格外亮眼的一年。我们也分享了这一行业红利，但这背后也存在着隐忧。</p><p>公司的传统业务（目前仍是最大的业务板块）聚焦于特殊保单与非标准承保标的。当行业整体承保亏损导致标准市场承保能力收紧时，保险经纪商会转向我们，公司业务规模便会大幅增长。几年前正是这样的市场环境，这也是1970年和1971年公司直接保费规模大幅攀升的核心原因。而如今，全行业承保业务已进入高盈利区间，更多保险公司开始争抢不久前还拒之门外的投保标的，部分地区的费率也已出现下调。我们始终将承保盈利作为首要目标，这意味着1972年国民赔偿保险公司的直接保费规模很可能出现大幅下滑。杰克·林沃尔特与菲尔·利舍始终以业内极少有人能及的水准引领着这项业务的发展。</p><p>在乔治·杨的卓越努力下，公司的再保险业务仅用两年时间就发展到了可观的规模，而它也面临着几乎相同的市场环境。我们于1969年末进入再保险市场，彼时市场费率大幅上调、承保能力紧缺。1971年再保险行业盈利水平格外突出，而目前我们已看到市场出现费率下调，同时大量资金雄厚、风格激进的新竞争对手纷纷成立。这些下调后的费率，往往伴随着更高的风险敞口。在这一背景下，我们预计1972年再保险业务规模将有所收缩。在保险业务整体经营中，我们从未设定规模目标——在再保险业务中更是如此，因为只要放弃盈利标准，几乎任何规模的业务都能拿到。当巨灾发生、承保业绩恶化时，我们计划储备充足的资金，以承接届时将出现的、定价合理的大规模业务。</p><p>1970年，我们成立了康哈斯克意外保险公司，正式启动&quot;本土州&quot;保险业务。截至目前，该业务在市场营销与承保两端均表现良好。因此，我们进一步推广这一模式，于1971年在明尼苏达州成立了莱克兰火灾与意外保险公司，并于1972年成立了德克萨斯联合保险公司。每家公司都将深耕单一州市场，致力于为当地的保险经纪机构与投保人，融合&quot;大公司的服务能力&quot;与&quot;小公司的本地化触达和市场敏感度&quot;。约翰·林沃尔特自该业务启动以来便担任总负责人。他凭借勤奋的工作、出众的想象力与智慧，将一个商业构想落地为组织完善的业务。目前&quot;本土州&quot;系列公司规模仍很小，1971年保费规模仅略超150万美元。预计1972年保费规模将实现翻倍以上，我们也将建立起更可靠的业务基数，以此评估承保业绩。</p><p>1971年的一大亮点，是我们完成了对芝加哥家庭与汽车保险公司的收购。维克托·拉布以一笔小额初始投资，将这家公司打造为库克县主要的汽车保险公司，1971年保费规模约750万美元。维克托与杰克·林沃尔特、吉恩·阿贝格一脉相承，既拥有实现持续盈利的经营天赋，也对自身业务满怀热忱。这三位管理者均白手起家打造了自己的公司，在以现金出售全部股权后，依然完整保留着对公司一如既往的主人翁精神与自豪感。</p><p>自成立以来，维克托让家庭与汽车保险公司的初始股权实现了多次增值，但他的经营理念与才华始终受限于公司的资本规模。我们已为该公司补充了资本金，使其能够设立分支机构，将其高度聚焦、本地化的市场营销与理赔模式，推广至其他人口密集地区。</p><p>总而言之，1972年家庭与汽车保险公司带来的业务增量，叠加&quot;本土州&quot;业务的增长，能否抵消国民赔偿保险公司直接业务与再保险业务可能出现的下滑，目前仍未可知。但1970年和1971年保费规模的大幅增长，为我们在高利率时期带来了额外的投资资金，这将在未来数年持续为公司创造收益。因此，尽管保费规模的前景并不亮眼，1972年保险业务的投资收益与整体盈利前景仍较为可观。</p><h3 id="银行业务" tabindex="-1">银行业务 <a class="header-anchor" href="#银行业务" aria-label="Permalink to &quot;银行业务&quot;">​</a></h3><p>以存款收益率衡量，我们的银行子公司罗克福德市伊利诺伊国民银行与信托公司，持续领跑行业。1971年，该行税后平均存款收益率远超2%，同时实现了：（1）除极偶尔的准备金平衡交易外，未使用任何借入资金；（2）保持远高于行业平均水平的流动性；（3）贷款损失率远低于行业平均；（4）定期存款占比超50%，且全年所有居民储蓄账户均按监管允许的最高利率付息。这一业绩充分印证了吉恩·阿贝格与鲍勃·克莱恩卓越的管理能力。</p><p>1971年，全银行业贷款与投资的实际利率均出现大幅下滑。过去几年，与行业平均水平相比，伊利诺伊国民银行的存款结构发生了更大幅度的转变，从活期存款转向成本高得多的定期存款。例如，存款利息支出已从1969年的不足170万美元，升至1971年的超270万美元。尽管如此，该行依然保持了出众的盈利能力。本年度我们加大了营销力度，取得了优异的成果。</p><p>当前利率水平已较1971年进一步走低，银行业1972年的盈利增长将面临困境。伊利诺伊国民银行的存款增长仍集中在定期存款领域，而这类存款目前仅能带来微薄的增量收益。要想在1972年维持1971年的盈利水平，该行必须实施极为严格的成本管控。</p><h3 id="财务事项" tabindex="-1">财务事项 <a class="header-anchor" href="#财务事项" aria-label="Permalink to &quot;财务事项&quot;">​</a></h3><p>1971年初，鉴于保险子公司保费规模持续增长，我们对伯克希尔·哈撒韦的银行贷款进行了重组，为保险子公司补充了额外资本金。而当年晚些时候出现收购家庭与汽车保险公司的机会时，这笔融资被证明尤为及时。</p><p>我们的保险与银行子公司与公众之间存在受托责任关系。我们始终坚信，必须以极为稳健的财务状况开展经营，确保能够毫无异议地履行自身责任。因此，我们将持续规划财务发展，在子公司与母公司层面均最大化财务实力。</p><p>沃伦·E·巴菲特</p><p>董事会主席</p><p>1972年3月13日</p><hr><p><em>完整财务报表详见原始年报</em></p>',36)])])}const _=e(o,[["render",l]]);export{c as __pageData,_ as default};
